import { useState } from "react";

const NAV_LINKS = [
  { label: "Produkt", sub: ["Features", "Integrationen", "Roadmap", "Changelog"] },
  { label: "Lösungen", sub: ["Für Teams", "Für Agenturen", "Enterprise"] },
  { label: "Preise", sub: [] },
  { label: "Docs", sub: [] },
];

export default function NavbarMegaMenu01() {
  const [open, setOpen] = useState<string | null>(null);
  return (
    <header className="sticky top-0 z-50 border-b border-slate-100 bg-white/95 backdrop-blur">
      <div className="mx-auto flex h-16 max-w-7xl items-center justify-between px-6">
        <a href="/" className="text-lg font-bold text-slate-900">{{projectName}}</a>
        <nav className="hidden items-center gap-1 md:flex">
          {NAV_LINKS.map((link) => (
            <div key={link.label} className="relative">
              <button
                className="flex items-center gap-1 rounded-lg px-3 py-2 text-sm font-medium text-slate-600 transition hover:bg-slate-100 hover:text-slate-900"
                onMouseEnter={() => link.sub.length ? setOpen(link.label) : setOpen(null)}
                onMouseLeave={() => setOpen(null)}
              >
                {link.label}
                {link.sub.length > 0 && <span className="text-[10px] text-slate-400">▾</span>}
              </button>
              {open === link.label && link.sub.length > 0 && (
                <div
                  className="absolute top-full left-0 mt-1 w-44 rounded-xl border border-slate-200 bg-white p-2 shadow-xl"
                  onMouseEnter={() => setOpen(link.label)}
                  onMouseLeave={() => setOpen(null)}
                >
                  {link.sub.map((s) => (
                    <a key={s} href="#" className="block rounded-lg px-3 py-2 text-sm text-slate-600 transition hover:bg-slate-50 hover:text-slate-900">
                      {s}
                    </a>
                  ))}
                </div>
              )}
            </div>
          ))}
        </nav>
        <div className="flex items-center gap-2">
          <button className="hidden rounded-lg px-4 py-2 text-sm font-semibold text-slate-600 transition hover:bg-slate-100 md:block">
            Anmelden
          </button>
          <button className="rounded-xl bg-slate-900 px-4 py-2 text-sm font-bold text-white transition hover:bg-slate-700">
            Gratis starten
          </button>
        </div>
      </div>
    </header>
  );
}

